"use client";

import { forwardRef } from "react";
import * as LabelPrimitive from "@radix-ui/react-label";
import { cva, type VariantProps } from "class-variance-authority";
import { cn } from "#lib/utils";

const labelVariants = cva(
  "font-sans items-center flex gap-2 text-sm font-medium select-none group-data-[disabled=true]:pointer-events-none group-data-[disabled=true]:opacity-50 peer-disabled:cursor-not-allowed peer-disabled:opacity-50",
);

const Label = forwardRef<
  React.ComponentRef<typeof LabelPrimitive.Root>,
  React.ComponentPropsWithoutRef<typeof LabelPrimitive.Root> &
    VariantProps<typeof labelVariants>
>(({ className, ...props }, ref) => {
  return (
    <LabelPrimitive.Root
      className={cn(labelVariants(), className)}
      data-slot="label"
      ref={ref}
      {...props}
    />
  );
});

export type LabelProps = {
  label?: string;
  id: string;
  required?: boolean;
  showRequired?: boolean;
} & {
  [x: string]: unknown;
};

// biome-ignore lint/suspicious/noExplicitAny: Can be any type of input component
const withLabel = (Component: React.ComponentType<any>) => {
  return ({
    label,
    id,
    required,
    showRequired = true,
    ...props
  }: LabelProps) => {
    if (!label) {
      return <Component {...props} />;
    }

    const labelProps = {
      // do not add htmlFor if id is not provided, in cases of being used for non-input elements
      ...(id ? { htmlFor: id } : {}),
    };

    return (
      <div className="flex flex-col flex-1 gap-2">
        <Label {...labelProps} className={cn(required ? "gap-1" : "")}>
          {label}{" "}
          {showRequired ? (
            required ? (
              <span className="text-xs text-neutral-500">required</span>
            ) : (
              <span className="text-xs font-normal text-neutral-500">
                optional
              </span>
            )
          ) : null}
        </Label>
        <Component id={id} {...props} />
      </div>
    );
  };
};

const LabelWrapper = ({
  label,
  id,
  children,
  required,
  showRequired = true,
  ...props
}: React.PropsWithChildren<LabelProps>) => {
  if (!label) {
    return children;
  }

  const labelProps = {
    ...props,
    // do not add htmlFor if id is not provided, in cases of being used for non-input elements
    ...(id ? { htmlFor: id } : {}),
  };

  return (
    <div className="flex flex-col gap-2">
      <Label {...labelProps} className={cn(required ? "gap-1" : "")}>
        {label}{" "}
        {showRequired ? (
          required ? (
            <span className="text-xs text-neutral-500">required</span>
          ) : (
            <span className="text-xs font-normal text-neutral-500">
              optional
            </span>
          )
        ) : null}
      </Label>
      {children}
    </div>
  );
};

export { Label, withLabel, LabelWrapper };

